function parseQueryString(input) {
  if (!input || typeof input !== 'string') return {};
  const str = input.startsWith('?') ? input.slice(1) : input;
  if (!str) return {};
  const result = {};
  const pairs = str.split('&');
  for (const pair of pairs) {
    if (!pair) continue;
    const eqIdx = pair.indexOf('=');
    let key, value;
    if (eqIdx === -1) {
      key = pair;
      value = '';
    } else {
      key = pair.slice(0, eqIdx);
      value = pair.slice(eqIdx + 1);
    }
    let decodedKey, decodedValue;
    try { decodedKey = decodeURIComponent(key.replace(/\+/g, ' ')); } catch { decodedKey = key; }
    try { decodedValue = decodeURIComponent(value.replace(/\+/g, ' ')); } catch { decodedValue = value; }
    if (Object.prototype.hasOwnProperty.call(result, decodedKey)) {
      if (!Array.isArray(result[decodedKey])) result[decodedKey] = [result[decodedKey]];
      result[decodedKey].push(decodedValue);
    } else {
      result[decodedKey] = decodedValue;
    }
  }
  return result;
}

// Tests
const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };
const deepEq = (a, b) => JSON.stringify(a) === JSON.stringify(b);

// 1. Basic key=value with leading ?
assert(deepEq(parseQueryString('?a=1&b=two'), { a: '1', b: 'two' }), 'basic');
// 2. Missing ?
assert(deepEq(parseQueryString('a=1&b=two'), { a: '1', b: 'two' }), 'no question mark');
// 3. Repeated keys become array
assert(deepEq(parseQueryString('?a=1&a=2'), { a: ['1', '2'] }), 'repeated keys');
// 4. Empty value
assert(deepEq(parseQueryString('?a='), { a: '' }), 'empty value');
// 5. Percent-encoded characters
assert(deepEq(parseQueryString('?name=John%20Doe'), { name: 'John Doe' }), 'percent-encoded');
// 6. Blank input
assert(deepEq(parseQueryString(''), {}), 'blank input');
// 7. null input
assert(deepEq(parseQueryString(null), {}), 'null input');
// 8. Key without =
assert(deepEq(parseQueryString('?flag'), { flag: '' }), 'key without =');
// 9. Malformed escape sequence (e.g. %ZZ) - should not throw, return raw
const r = parseQueryString('?bad=%ZZ');
assert(r.bad === '%ZZ', 'malformed escape');
// 10. Only ?
assert(deepEq(parseQueryString('?'), {}), 'only ?');

console.log('All tests passed');
```

