function isPlainObject(val) {
  return val !== null && typeof val === 'object' && !Array.isArray(val) && Object.getPrototypeOf(val) === Object.prototype;
}

function deepMerge(a, b) {
  if (!isPlainObject(a) || !isPlainObject(b)) throw new TypeError('Both arguments must be plain objects');
  const result = {};
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  for (const key of keys) {
    const av = a[key], bv = b[key];
    if (key in a && key in b && isPlainObject(av) && isPlainObject(bv)) {
      result[key] = deepMerge(av, bv);
    } else if (key in b) {
      result[key] = Array.isArray(bv) ? [...bv] : bv;
    } else {
      result[key] = Array.isArray(av) ? [...av] : av;
    }
  }
  return result;
}

// Tests
const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };
const deepEq = (a, b) => JSON.stringify(a) === JSON.stringify(b);

// 1. Basic merge
assert(deepEq(deepMerge({a:1},{b:2}), {a:1,b:2}), 'basic merge');
// 2. Nested objects
assert(deepEq(deepMerge({a:{x:1}},{a:{y:2}}), {a:{x:1,y:2}}), 'nested merge');
// 3. b overwrites primitive
assert(deepEq(deepMerge({a:1},{a:2}), {a:2}), 'overwrite primitive');
// 4. Arrays overwrite (not merged)
assert(deepEq(deepMerge({a:[1,2]},{a:[3]}), {a:[3]}), 'array overwrite');
// 5. null value in b
assert(deepEq(deepMerge({a:1},{a:null}), {a:null}), 'null overwrite');
// 6. Missing key in b keeps a
assert(deepEq(deepMerge({a:1,b:2},{a:3}), {a:3,b:2}), 'missing key in b');
// 7. Conflicting types
assert(deepEq(deepMerge({a:{x:1}},{a:5}), {a:5}), 'conflict type');
// 8. Empty objects
assert(deepEq(deepMerge({},{}), {}), 'both empty');
// 9. Deep nesting
assert(deepEq(deepMerge({a:{b:{c:1}}},{a:{b:{d:2}}}), {a:{b:{c:1,d:2}}}), 'deep nesting');
// 10. No mutation of inputs
const x = {a:{b:1}}; const y = {a:{c:2}};
deepMerge(x, y);
assert(deepEq(x, {a:{b:1}}), 'no mutation of a');
assert(deepEq(y, {a:{c:2}}), 'no mutation of b');
// 11. Only in a
assert(deepEq(deepMerge({z:99},{}), {z:99}), 'only in a');

console.log('All tests passed');
```

