function debounce(fn, delay) {
  if (typeof fn !== 'function') throw new TypeError('fn must be a function');
  if (typeof delay !== 'number' || delay < 0) throw new RangeError('delay must be a non-negative number');
  let timer = null;
  function debounced(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => {
      timer = null;
      fn.apply(this, args);
    }, delay);
  }
  debounced.cancel = () => { clearTimeout(timer); timer = null; };
  return debounced;
}

// Tests using fake timers
let now = 0;
const originalSetTimeout = setTimeout;
const originalClearTimeout = clearTimeout;
let timers = [];
global.setTimeout = (fn, delay) => { const id = timers.length; timers.push({fn, time: now + delay, cancelled: false}); return id; };
global.clearTimeout = (id) => { if (timers[id]) timers[id].cancelled = true; };
const tick = (ms) => { now += ms; for (const t of timers) { if (!t.cancelled && t.time <= now) { t.cancelled = true; t.fn(); } } };

const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };

// 1. Delayed execution
timers = []; now = 0;
let called = 0;
const d1 = debounce(() => called++, 100);
d1(); tick(50); assert(called === 0, 'not called before delay');
tick(60); assert(called === 1, 'called after delay');

// 2. Multiple rapid calls - only last fires
timers = []; now = 0; called = 0;
const d2 = debounce(() => called++, 100);
d2(); tick(50); d2(); tick(50); d2(); tick(110);
assert(called === 1, 'only one call after rapid invocations');

// 3. Argument forwarding
timers = []; now = 0;
let lastArg;
const d3 = debounce((x) => { lastArg = x; }, 50);
d3(42); tick(60);
assert(lastArg === 42, 'argument forwarded');

// 4. this preservation
timers = []; now = 0;
let capturedThis;
const obj = { fn: debounce(function() { capturedThis = this; }, 50) };
obj.fn(); tick(60);
assert(capturedThis === obj, 'this preserved');

// 5. delay = 0
timers = []; now = 0; called = 0;
const d5 = debounce(() => called++, 0);
d5(); tick(0);
assert(called === 1, 'delay=0 fires immediately on tick');

// 6. Non-function throws
try { debounce('not a fn', 100); assert(false, 'should throw'); } catch(e) { assert(e instanceof TypeError, 'non-fn throws'); }

console.log('All tests passed');
```

