// Assumptions: Normalize to E.164 format: +[country][number]
// defaultCountry: 'US' (country code 1) if not specified
// Strip spaces, dashes, dots, parentheses
// Extensions not supported in E.164; strip them with warning
function normalizePhoneNumber(input, defaultCountry = 'US') {
  if (!input || typeof input !== 'string') return null;
  let s = input.trim();
  if (!s) return null;
  // Remove extensions like x123, ext.123
  s = s.replace(/\s*(x|ext\.?)\s*\d+$/i, '');
  // Remove formatting chars
  s = s.replace(/[\s().\-]/g, '');
  // Invalid chars check
  if (/[^0-9+]/.test(s)) return null;
  // Already has + prefix
  if (s.startsWith('+')) {
    if (/^\+\d{7,15}$/.test(s)) return s;
    return null;
  }
  // Remove leading 00
  if (s.startsWith('00')) s = '+' + s.slice(2);
  else if (defaultCountry === 'US') {
    if (s.startsWith('1') && s.length === 11) s = '+' + s;
    else if (s.length === 10) s = '+1' + s;
    else return null;
  } else {
    return null;
  }
  if (/^\+\d{7,15}$/.test(s)) return s;
  return null;
}

// Tests
const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };

// 1. Standard US number with formatting
assert(normalizePhoneNumber('(800) 555-1234') === '+18005551234', 'US with parens and dashes');
// 2. Leading country code
assert(normalizePhoneNumber('+44 20 7946 0958') === '+442079460958', 'UK with spaces');
// 3. Already normalized
assert(normalizePhoneNumber('+18005551234') === '+18005551234', 'already normalized');
// 4. Dots as separators
assert(normalizePhoneNumber('800.555.1234') === '+18005551234', 'dots');
// 5. With extension
assert(normalizePhoneNumber('(800) 555-1234 ext. 42') === '+18005551234', 'extension stripped');
// 6. Empty string
assert(normalizePhoneNumber('') === null, 'empty string');
// 7. null input
assert(normalizePhoneNumber(null) === null, 'null input');
// 8. Invalid characters
assert(normalizePhoneNumber('800-abc-1234') === null, 'invalid chars');
// 9. 00 prefix international
assert(normalizePhoneNumber('00442079460958') === '+442079460958', '00 prefix');
// 10. 11-digit US with leading 1
assert(normalizePhoneNumber('18005551234') === '+18005551234', '11-digit US');

console.log('All tests passed');
