function isValidIPv4(input) {
  if (typeof input !== 'string') return false;
  const parts = input.split('.');
  if (parts.length !== 4) return false;
  for (const part of parts) {
    if (part === '') return false;
    if (!/^\d+$/.test(part)) return false;
    if (part.length > 1 && part[0] === '0') return false; // no leading zeros
    const n = Number(part);
    if (n < 0 || n > 255) return false;
  }
  return true;
}

// Tests
const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };

assert(isValidIPv4('192.168.1.1') === true, 'valid private IP');
assert(isValidIPv4('0.0.0.0') === true, 'all zeros');
assert(isValidIPv4('255.255.255.255') === true, 'all 255');
assert(isValidIPv4('256.0.0.1') === false, 'octet > 255');
assert(isValidIPv4('192.168.1') === false, 'only 3 parts');
assert(isValidIPv4('192.168.1.1.1') === false, '5 parts');
assert(isValidIPv4('192.168.01.1') === false, 'leading zero');
assert(isValidIPv4('192.168.1.') === false, 'trailing dot');
assert(isValidIPv4('') === false, 'empty string');
assert(isValidIPv4('abc.def.ghi.jkl') === false, 'non-numeric');
assert(isValidIPv4('192.168.1.-1') === false, 'negative octet');
assert(isValidIPv4(null) === false, 'null');
assert(isValidIPv4('192.168. 1.1') === false, 'space in octet');
assert(isValidIPv4('1.2.3.4.') === false, 'trailing dot 2');

console.log('All tests passed');
```

