function unflattenObject(obj) {
  if (obj === null || typeof obj !== 'object') throw new TypeError('Input must be a plain object');
  const result = {};
  for (const [key, value] of Object.entries(obj)) {
    const parts = key.split('.');
    let current = result;
    for (let i = 0; i < parts.length - 1; i++) {
      const part = parts[i];
      if (current[part] === undefined) current[part] = {};
      else if (typeof current[part] !== 'object' || current[part] === null) {
        throw new Error(`Conflict at key: ${parts.slice(0, i+1).join('.')}`);
      }
      current = current[part];
    }
    current[parts[parts.length - 1]] = value;
  }
  return result;
}

// Tests
const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };
const deepEq = (a, b) => JSON.stringify(a) === JSON.stringify(b);

// 1. Basic
assert(deepEq(unflattenObject({'a.b':1}), {a:{b:1}}), 'basic');
// 2. Deep
assert(deepEq(unflattenObject({'a.b.c':2}), {a:{b:{c:2}}}), 'deep');
// 3. Multiple keys
assert(deepEq(unflattenObject({'a.b':1,'a.c':2}), {a:{b:1,c:2}}), 'multiple');
// 4. Already flat
assert(deepEq(unflattenObject({a:1,b:2}), {a:1,b:2}), 'flat');
// 5. Empty object
assert(deepEq(unflattenObject({}), {}), 'empty');
// 6. Mixed depth
assert(deepEq(unflattenObject({a:1,'b.c':2}), {a:1,b:{c:2}}), 'mixed depth');
// 7. Null value
