function parseCsvLine(line, delimiter = ',') {
  if (typeof line !== 'string') throw new TypeError('line must be a string');
  const fields = [];
  let i = 0;
  while (i <= line.length) {
    if (i === line.length) { fields.push(''); break; }
    if (line[i] === '"') {
      // quoted field
      let field = '';
      i++;
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i+1] === '"') { field += '"'; i += 2; }
          else { i++; break; }
        } else {
          field += line[i++];
        }
      }
      fields.push(field);
      // expect delimiter or end
      if (i < line.length && line[i] === delimiter) i++;
      else if (i < line.length) throw new Error('Malformed CSV: unexpected char after quoted field');
    } else {
      let field = '';
      while (i < line.length && line[i] !== delimiter) field += line[i++];
      fields.push(field);
      if (i < line.length) i++; // skip delimiter
      else break;
    }
  }
  // Handle empty line
  if (line === '') return [''];
  return fields;
}

// Tests
const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };
const deepEq = (a, b) => JSON.stringify(a) === JSON.stringify(b);

// 1. Basic
assert(deepEq(parseCsvLine('a,b,c'), ['a','b','c']), 'basic');
// 2. Quoted field
assert(deepEq(parseCsvLine('"hello world",b'), ['hello world','b']), 'quoted field');
// 3. Quoted field with comma inside
assert(deepEq(parseCsvLine('"a,b",c'), ['a,b','c']), 'comma in quotes');
// 4. Escaped quote
assert(deepEq(parseCsvLine('"say \"\"hi\"\"",b'), ['say "hi"','b']), 'escaped quote');
// 5. Empty fields
assert(deepEq(parseCsvLine(',b,'), ['','b','']), 'empty fields');
// 6. Empty string
assert(deepEq(parseCsvLine(''), ['']), 'empty string');
// 7. Single field
assert(deepEq(parseCsvLine('only'), ['only']), 'single field');
// 8. Newline inside quotes
assert(deepEq(parseCsvLine('"line\none",b'), ['line\none','b']), 'newline in quotes');

console.log('All tests passed');
```

