// Title case: capitalize first letter of each word, lowercase rest
// Words: split on whitespace boundaries
// Small words (articles, conjunctions, prepositions) stay lowercase unless first/last word
const SMALL_WORDS = new Set(['a','an','the','and','but','or','for','nor','on','at','to','by','in','of','up','as','is']);

function toTitleCase(input) {
  if (typeof input !== 'string') return '';
  if (!input.trim()) return input;
  const words = input.split(/(\s+)/);
  const result = [];
  let wordIndex = 0;
  const wordCount = words.filter(w => !/^\s+$/.test(w)).length;
  let realWordIdx = 0;
  for (const token of words) {
    if (/^\s+$/.test(token)) { result.push(token); continue; }
    const lower = token.toLowerCase();
    const isFirst = realWordIdx === 0;
    const isLast = realWordIdx === wordCount - 1;
    if (!isFirst && !isLast && SMALL_WORDS.has(lower)) {
      result.push(lower);
    } else {
      result.push(lower.charAt(0).toUpperCase() + lower.slice(1));
    }
    realWordIdx++;
  }
  return result.join('');
}

// Tests
const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };

assert(toTitleCase('hello world') === 'Hello World', 'basic');
assert(toTitleCase('the quick brown fox') === 'The Quick Brown Fox', 'the is first');
assert(toTitleCase('war and peace') === 'War and Peace', 'small word in middle');
assert(toTitleCase('') === '', 'empty string');
