function binarySearchRange(nums, target) {
  if (!Array.isArray(nums)) throw new TypeError('nums must be an array');
  function findFirst() {
    let lo = 0, hi = nums.length - 1, idx = -1;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (nums[mid] === target) { idx = mid; hi = mid - 1; }
      else if (nums[mid] < target) lo = mid + 1;
      else hi = mid - 1;
    }
    return idx;
  }
  function findLast() {
    let lo = 0, hi = nums.length - 1, idx = -1;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (nums[mid] === target) { idx = mid; lo = mid + 1; }
      else if (nums[mid] < target) lo = mid + 1;
      else hi = mid - 1;
    }
    return idx;
  }
  return [findFirst(), findLast()];
}

// Tests
