async function retryAsync(task, maxAttempts, delayMs = 0) {
  if (typeof task !== 'function') throw new TypeError('task must be a function');
  if (!Number.isInteger(maxAttempts) || maxAttempts < 1) throw new RangeError('maxAttempts must be >= 1');
  let lastError;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await task(attempt);
    } catch (err) {
      lastError = err;
      if (attempt < maxAttempts && delayMs > 0) {
        await new Promise(resolve => setTimeout(resolve, delayMs));
      }
    }
  }
  throw lastError;
}

// Tests
async function runTests() {
  const assert = (cond, msg) => { if (!cond) throw new Error('FAIL: ' + msg); };

  // 1. Succeeds on first attempt
  let calls = 0;
  const r1 = await retryAsync(() => { calls++; return Promise.resolve(42); }, 3);
  assert(r1 === 42 && calls === 1, 'succeeds first attempt');

  // 2. Retries and succeeds
  calls = 0;
  const r2 = await retryAsync(() => {
    calls++;
    if (calls < 3) return Promise.reject(new Error('not yet'));
    return Promise.resolve('ok');
  }, 5);
  assert(r2 === 'ok' && calls === 3, 'retries until success');

  // 3. Exhausts all attempts and throws
  calls = 0;
  try {
    await retryAsync(() => { calls++; return Promise.reject(new Error('always fails')); }, 3);
    assert(false, 'should have thrown');
  } catch(e) {
    assert(calls === 3 && e.message === 'always fails', 'throws after max attempts');
  }

  // 4. maxAttempts = 1 no retry
  calls = 0;
  try {
    await retryAsync(() => { calls++; throw new Error('fail'); }, 1);
  } catch(e) {
    assert(calls === 1, 'maxAttempts=1 no retry');
  }

  // 5. attempt number passed to task
  const attempts = [];
  try {
    await retryAsync((n) => { attempts.push(n); return Promise.reject(new Error('x')); }, 3, 0);
  } catch {}
  assert(JSON.stringify(attempts) === '[1,2,3]', 'attempt numbers passed');

  // 6. Non-function throws
  try { await retryAsync('not fn', 3); assert(false,'should throw'); } catch(e) { assert(e instanceof TypeError, 'non-fn throws'); }

  console.log('All tests passed');
}

runTests().catch(console.error);
