function formatDuration(seconds) {
  if (typeof seconds !== 'number' || isNaN(seconds)) throw new TypeError('seconds must be a number');
  if (seconds < 0) throw new RangeError('seconds must be non-negative');
  const total = Math.floor(seconds);
  if (total === 0) return '0s';
  const units = [
    [86400 * 365, 'y'],
    [86400 * 30, 'mo'],
    [86400, 'd'],
    [3600, 'h'],
    [60, 'm'],
    [1, 's']
  ];
  const parts = [];
  let remaining = total;
  for (const [unit, label] of units) {
    if (remaining >= unit) {
      parts.push(`${Math.floor(remaining / unit)}${label}`);
      remaining %= unit;
    }
  }
  return parts.join(' ');
}

