function nearestPalindrome(n) {
  const num = BigInt(n);
  const s = String(n);
  const len = s.length;
  const candidates = [];
  // All 9s of len-1
  candidates.push(BigInt('9'.repeat(len - 1) || '0'));
  // 10...01 of len+1
  candidates.push(BigInt('1' + '0'.repeat(len - 1) + '1'));
  // Mirror middle variants
  const mid = Math.ceil(len / 2);
  const prefix = BigInt(s.slice(0, mid));
  for (const delta of [-1n, 0n, 1n]) {
    const p = prefix + delta;
    let ps = String(p);
    const full = len % 2 === 0 ? ps + ps.split('').reverse().join('') : ps + ps.slice(0,-1).split('').reverse().join('');
    candidates.push(BigInt(full));
  }
  let best = null;
  for (const c of candidates) {
    if (c === num) continue;
    const diff = c > num ? c - num : num - c;
    if (best === null) { best = c; continue; }
    const bestDiff = best > num ? best - num : num - best;
    if (diff < bestDiff || (diff === bestDiff && c < best)) best = c;
  }
  return String(best);
}

