function knapsack01(items, capacity) {
  const n = items.length;
  const dp = Array(n+1).fill(null).map(() => Array(capacity+1).fill(0));
  for (let i = 1; i <= n; i++) {
    const { weight, value } = items[i-1];
    for (let w = 0; w <= capacity; w++) {
      dp[i][w] = dp[i-1][w];
      if (weight <= w) dp[i][w] = Math.max(dp[i][w], dp[i-1][w-weight] + value);
    }
  }
  return dp[n][capacity];
}

const assert = require('assert');
assert.strictEqual(knapsack01([{weight:1,value:1},{weight:2,value:6},{weight:3,value:10},{weight:5,value:16}], 7), 22);
assert.strictEqual(knapsack01([], 10), 0); // empty items
assert.strictEqual(knapsack01([{weight:5,value:10}], 4), 0); // item too heavy
assert.strictEqual(knapsack01([{weight:5,value:10}], 5), 10); // exactly fits
assert.strictEqual(knapsack01([{weight:1,value:1}], 0), 0); // zero capacity
assert.strictEqual(knapsack01([{weight:2,value:3},{weight:3,value:4}], 5), 7); // both fit
console.log('All knapsack01 tests passed');
