assert.strictEqual(longestCommonPrefix(['']), ''); // single empty string
assert.strictEqual(longestCommonPrefix(['abc']), 'abc'); // single word
assert.strictEqual(longestCommonPrefix(['abc','abc']), 'abc'); // identical words
assert.strictEqual(longestCommonPrefix(['a','ab','abc']), 'a');
assert.strictEqual(longestCommonPrefix(['prefix','pre','prevent']), 'pre');
