function balancedBrackets(input) {
  const stack = [];
  const pairs = { ')':'(', ']':'[', '}':'{' };
  for (const ch of input) {
    if ('([{'.includes(ch)) stack.push(ch);
    else if (')]}'.includes(ch)) {
      if (stack.pop() !== pairs[ch]) return false;
    }
  }
  return stack.length === 0;
}

const assert = require('assert');
assert.strictEqual(balancedBrackets('()[]{}'), true);
assert.strictEqual(balancedBrackets('([{}])'), true);
assert.strictEqual(balancedBrackets('(]'), false);
assert.strictEqual(balancedBrackets(''), true); // empty is balanced
assert.strictEqual(balancedBrackets('{hello[world]}'), true); // with non-bracket chars
assert.strictEqual(balancedBrackets('((()'), false); // unclosed
assert.strictEqual(balancedBrackets(')))'), false); // extra close
assert.strictEqual(balancedBrackets('([)]'), false); // interleaved
console.log('All balancedBrackets tests passed');
